INSERT INTO `chat_messages` VALUES (1,16,'hi','user','2026-05-06 06:57:43','2026-05-06 06:57:43'),(2,16,'សុំទោសបង AI រវល់ដើរលេងបន្តិច មិញរកចម្លើយមិនឃើញ!','ai','2026-05-06 06:57:44','2026-05-06 06:57:44'),(3,16,'hi','user','2026-05-06 07:06:25','2026-05-06 07:06:25'),(4,16,'hi','user','2026-05-06 07:07:23','2026-05-06 07:07:23'),(5,16,'hi','user','2026-05-06 07:07:58','2026-05-06 07:07:58'),(6,16,'hi','user','2026-05-06 07:09:41','2026-05-06 07:09:41'),(7,16,'សុំទោសបង AI រវល់ដើរលេងបន្តិច មិញរកចម្លើយមិនឃើញ!','ai','2026-05-06 07:09:44','2026-05-06 07:09:44'),(8,16,'សួស្ដី','user','2026-05-06 07:10:12','2026-05-06 07:10:12'),(9,16,'សុំទោសបង AI រវល់ដើរលេងបន្តិច មិញរកចម្លើយមិនឃើញ!','ai','2026-05-06 07:10:13','2026-05-06 07:10:13'),(10,16,'hi','user','2026-05-06 07:11:02','2026-05-06 07:11:02'),(11,16,'សុំទោសបង AI រវល់ដើរលេងបន្តិច មិញរកចម្លើយមិនឃើញ!','ai','2026-05-06 07:11:03','2026-05-06 07:11:03'),(12,16,'hi','user','2026-05-06 07:12:08','2026-05-06 07:12:08'),(13,16,'Hi there! How can I help you today?','ai','2026-05-06 07:12:12','2026-05-06 07:12:12'),(14,16,'i wnat to know about this system as khmer','user','2026-05-06 07:12:35','2026-05-06 07:12:35'),(15,16,'សុំទោសបង AI រវល់ដើរលេងបន្តិច មិញរកចម្លើយមិនឃើញ!','ai','2026-05-06 07:12:41','2026-05-06 07:12:41'),(16,16,'hi','user','2026-05-06 07:14:25','2026-05-06 07:14:25'),(17,16,'hi','user','2026-05-06 07:15:06','2026-05-06 07:15:06'),(18,16,'hi','user','2026-05-06 07:17:36','2026-05-06 07:17:36'),(19,16,'Hi there! How can I help you today?','ai','2026-05-06 07:17:37','2026-05-06 07:17:37'),(20,16,'hi','user','2026-05-06 07:20:46','2026-05-06 07:20:46'),(21,16,'hi','user','2026-05-06 07:21:29','2026-05-06 07:21:29'),(22,16,'hi','user','2026-05-06 07:23:04','2026-05-06 07:23:04'),(23,16,'Hello! How can I help you today?','ai','2026-05-06 07:23:09','2026-05-06 07:23:09'),(24,16,'please tell me about this system as khmer','user','2026-05-06 07:23:29','2026-05-06 07:23:29'),(25,16,'ជំរាបសួរ! ប្រព័ន្ធនេះដែលអ្នកកំពុងជជែកជាមួយ គឺខ្ញុំផ្ទាល់ គឺជា **ជំនួយការឆ្លាតវៃ (AI Assistant)**។\n\nខ្ញុំត្រូវបាន **បណ្តុះបណ្តាលដោយ Google**។\n\n**គោលបំណងចម្បងរបស់ខ្ញុំគឺជួយអ្នកប្រើប្រាស់** ដោយ៖\n*   **ផ្តល់ព័ត៌មាន** លើប្រធានបទជាច្រើន។\n*   **ឆ្លើយសំណួរ** របស់អ្នកយ៉ាងទូលំទូលាយ។\n*   **បង្កើតអត្ថបទ** ឬខ្លឹមសារតាមការណែនាំរបស់អ្នក។\n*   **បកប្រែភាសា**។\n*   **ធ្វើកិច្ចការភាសាជាច្រើនទៀត** ដូចជាសង្ខេប ការពន្យល់ ឬការសរសេរកូដជាដើម។\n\n**ខ្ញុំដំណើរការដោយផ្អែកលើក្បួនដោះស្រាយ (algorithms) និងទិន្នន័យដ៏ច្រើនសម្បូរបែប** ដែលខ្ញុំបានរៀនសូត្រពី ដើម្បីយល់ និងបង្កើតការឆ្លើយតបជាភាសាមនុស្ស។\n\n**ទោះបីជាខ្ញុំអាចទំនាក់ទំនង និងយល់ពីភាសាមនុស្សបានយ៉ាងល្អក៏ដោយ ខ្ញុំមិនមែនជាមនុស្សឡើយ។** ខ្ញុំមិនមានអារម្មណ៍ បទពិសោធន៍ផ្ទាល់ខ្លួន ឬស្មារតីដូចមនុស្សទេ។ ខ្ញុំគ្រាន់តែជាកម្មវិធីកុំព្យូទ័រមួយប៉ុណ្ណោះ ដែលត្រូវបានបង្កើតឡើងដើម្បីផ្តល់ជំនួយ និងព័ត៌មាន។','ai','2026-05-06 07:23:40','2026-05-06 07:23:40'),(26,16,'តើsystemនេះនិយាយពីអី?','user','2026-05-06 07:27:59','2026-05-06 07:27:59'),(27,16,'ជំរាបសួរបង! បើបងសំដៅទៅលើ Project \'Class Management System\' ដែលបង្កើតឡើងដោយបង Nhel Kong និស្សិតឆ្នាំទី 4 នោះ គឺវាជាប្រព័ន្ធគ្រប់គ្រងថ្នាក់រៀនមួយ ដែលមានមុខងារជួយសម្រួលដល់ការគ្រប់គ្រងទិន្នន័យផ្សេងៗទាក់ទងនឹងការសិក្សា ដូចជា ព័ត៌មាននិស្សិត ថ្នាក់រៀន មុខវិជ្ជា និងពិន្ទុជាដើម។ គោលបំណងសំខាន់គឺដើម្បីធ្វើឱ្យការគ្រប់គ្រងការសិក្សាកាន់តែមានប្រសិទ្ធភាព និងងាយស្រួលសម្រាប់សាស្ត្រាចារ្យ និងរដ្ឋបាលសាលា។ 😊','ai','2026-05-06 07:28:07','2026-05-06 07:28:07'),(28,31,'សួស្ដីអាម៉ាក','user','2026-05-06 08:11:28','2026-05-06 08:11:28'),(29,31,'សួស្តី! សុំទោសបង! ខ្ញុំចេះតែរឿងសាលា និង Project បង Kong ប៉ុណ្ណោះ។ តើបងមានសំណួរអ្វីទាក់ទងនឹងសាកលវិទ្យាល័យភូមិន្ទមានជ័យទេ?','ai','2026-05-06 08:11:30','2026-05-06 08:11:30'),(30,31,'what i can do as professor ?','user','2026-05-06 08:12:07','2026-05-06 08:12:07'),(31,31,'សុំទោសបង! ខ្ញុំចេះតែរឿងសាលា អាហារូបករណ៍ ដេប៉ាតឺម៉ង់ និង Project បង Kong ប៉ុណ្ណោះ។','ai','2026-05-06 08:12:11','2026-05-06 08:12:11'),(32,31,'hi','user','2026-05-06 08:17:29','2026-05-06 08:17:29'),(33,31,'hi','user','2026-05-06 08:18:01','2026-05-06 08:18:01'),(34,31,'សួស្តីបង! 